#include <bits/stdc++.h>
using namespace std;
#define int long long
#define pii pair<int,int>
#define x first
#define y second
const int dk[][2]= {1,0,0,1,-1,0,0,-1};
void slove(int n,int m) {
	vector<string> a(n);
	deque<pii> dq;
	vector<vector<int>> vis(n,vector<int>(m));
	for(int i=0; i<n; i++) {
		cin>>a[i];
		for(int j=0;j<m;j++){
			vis[i][j]=0x3fffffff;
		}
	}
	int x1,x2,s1,s2;
	cin>>x1>>x2>>s1>>s2;
	vis[x1][x2]=0;
	dq.push_front({x1,x2});
	while(dq.size()) {
		int i=dq.front().x,j=dq.front().y;
		dq.pop_front();
		for(int k=0; k<4; k++) {
			int ni=i+dk[k][0],nj=j+dk[k][1];
			if(ni<0||ni>=n||nj<0||nj>=m) {
				continue;
			}
			if(a[ni][nj]!=a[i][j]&&vis[ni][nj]>vis[i][j]+1) {
				dq.push_back({ni,nj});
				vis[ni][nj]=vis[i][j]+1;
			}
			if(a[ni][nj]==a[i][j]&&vis[ni][nj]>vis[i][j]) {
				dq.push_front({ni,nj});
				vis[ni][nj]=vis[i][j];
			}
		}
	}
	cout<<vis[s1][s2]<<"\n";
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	while(1) {
		int n,m;
		cin>>n>>m;
		if(n==0&&m==0) {
			break;
		}
		slove(n,m);
	}
	return 0;
}
